// Build 10-day date windows from max(year_floor, today-2-lookback) to today-2.
// CLAMPED at year_floor (2026-01-01) so pre-2026 data is never fetched
// (reporting is 2026-only). GSC data lags ~2 days, so the window ends at today-2.
const cfg = $('Config').first().json;
const lookback = Number(cfg.lookback_days) || 7;
const floorStr = String(cfg.year_floor || '2026-01-01');
const STEP = 10;   // days per window
const LAG = 2;     // GSC reporting lag

const ymd = (d) => d.toISOString().slice(0, 10);
const addDays = (d, n) => { const x = new Date(d.getTime()); x.setUTCDate(x.getUTCDate() + n); return x; };

const now = new Date();
const end = addDays(now, -LAG);                 // endDate = today-2
let start = addDays(now, -(lookback + LAG));    // lookback window start
const floor = new Date(floorStr + 'T00:00:00Z');
if (start.getTime() < floor.getTime()) start = floor;  // never before 2026-01-01

const windows = [];
let ws = new Date(start.getTime());
while (ws.getTime() <= end.getTime()) {
  let we = addDays(ws, STEP - 1);
  if (we.getTime() > end.getTime()) we = end;
  windows.push({ json: { startDate: ymd(ws), endDate: ymd(we) } });
  ws = addDays(we, 1);
}
if (windows.length === 0) windows.push({ json: { startDate: ymd(end), endDate: ymd(end) } });
return windows;

// GSC date x query for the CURRENT 10-day window (may span multiple pages) ->
// fact_seo_query_daily rows. No throw on empty (a backfill must survive a thin
// window); auth/config errors still surface at the HTTP node.
const items = $input.all();
let rows = [];
for (const it of items) { rows = rows.concat((it.json && it.json.rows) || []); }
const out = [];
for (const r of rows) {
  const keys = r.keys || [];
  const date = String(keys[0] || '');
  const query = String(keys[1] || '');
  if (date.length !== 10 || !query) continue;
  out.push({
    activity_date: date,
    query: query,
    clicks: Number(r.clicks) || 0,
    impressions: Number(r.impressions) || 0,
    ctr: Number(r.ctr) || 0,
    avg_position: Number((Number(r.position) || 0).toFixed(2)),
    source: 'gsc'
  });
}
return out.map((json) => ({ json }));
